import React, { useState } from 'react';
import Header from './components/Header';
import ImageUploader from './components/ImageUploader';
import ResultDisplay from './components/ResultDisplay';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

function App() {
  const [image,    setImage]    = useState(null);   // File object
  const [imageUrl, setImageUrl] = useState(null);   // Object URL for preview
  const [result,   setResult]   = useState(null);   // API response
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState(null);

  // ── Handlers ──────────────────────────────────────────────────────────────
  const handleImageSelect = (file, url) => {
    // Revoke previous object URL to avoid memory leak
    if (imageUrl) URL.revokeObjectURL(imageUrl);
    setImage(file);
    setImageUrl(url);
    setResult(null);
    setError(null);
  };

  const handlePredict = async () => {
    if (!image) return;
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const body = new FormData();
      body.append('file', image);

      const res  = await fetch(`${API_URL}/predict`, { method: 'POST', body });
      const data = await res.json();

      if (!res.ok) throw new Error(data.error || `Server error ${res.status}`);
      setResult(data);
    } catch (err) {
      setError(
        err.message.includes('fetch')
          ? 'Could not reach the server. Make sure Flask is running on port 5000.'
          : err.message
      );
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    if (imageUrl) URL.revokeObjectURL(imageUrl);
    setImage(null);
    setImageUrl(null);
    setResult(null);
    setError(null);
  };

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div className="app">
      <Header />

      <main className="main-content">
        <div className="container">

          {/* Hero text */}
          <div className="hero-text">
            <h2>Identify Any Ghanaian Banknote Instantly</h2>
            <p>
              Upload a photo of a Ghana Cedi note and our AI model will
              recognise the denomination with high accuracy.
            </p>
          </div>

          {/* Upload + Result workspace */}
          <div className="workspace">
            <ImageUploader
              onImageSelect={handleImageSelect}
              imageUrl={imageUrl}
              loading={loading}
              onPredict={handlePredict}
              onReset={handleReset}
              hasImage={!!image}
            />

            {error && (
              <div className="error-banner" role="alert">
                <span className="error-icon">&#9888;</span>
                <span>{error}</span>
              </div>
            )}

            {(loading || result) && (
              <ResultDisplay result={result} loading={loading} />
            )}
          </div>

          {/* Feature cards */}
          <div className="feature-cards">
            <div className="feature-card">
              <div className="feature-icon">&#129504;</div>
              <h3>Deep Learning CNN</h3>
              <p>MobileNetV2 transfer learning trained on all 8 Ghana Cedi denominations</p>
            </div>
            <div className="feature-card">
              <div className="feature-icon">&#127919;</div>
              <h3>High Accuracy</h3>
              <p>Expected 85–95 % accuracy under varying lighting and angle conditions</p>
            </div>
            <div className="feature-card">
              <div className="feature-icon">&#9855;</div>
              <h3>Accessibility</h3>
              <p>Helps visually impaired individuals identify banknotes confidently</p>
            </div>
            <div className="feature-card">
              <div className="feature-icon">&#9889;</div>
              <h3>Real-Time</h3>
              <p>Fast inference via Flask REST API — results in under a second</p>
            </div>
          </div>

        </div>
      </main>

      <footer className="footer">
        <div className="footer-flag">
          <span style={{ background: '#CE1126' }} />
          <span style={{ background: '#FCD116' }} />
          <span style={{ background: '#006B3F' }} />
        </div>
        <p>
          Ghana Currency Recognition System &copy; {new Date().getFullYear()}
          &nbsp;&mdash;&nbsp; Built with React &amp; TensorFlow
        </p>
      </footer>
    </div>
  );
}

export default App;
